(function (window) {
  function JQueryLite(selector) {
    if (typeof selector === 'function') {
      if (document.readyState === 'loading') document.addEventListener('DOMContentLoaded', selector);
      else selector();
      return;
    }
    this.nodes = Array.prototype.slice.call(document.querySelectorAll(selector));
  }

  JQueryLite.prototype.val = function (value) {
    if (value === undefined) return this.nodes[0] ? this.nodes[0].value : undefined;
    this.nodes.forEach(function (node) { node.value = value; });
    return this;
  };
  JQueryLite.prototype.text = function (value) {
    if (value === undefined) return this.nodes[0] ? this.nodes[0].textContent : undefined;
    this.nodes.forEach(function (node) { node.textContent = value; });
    return this;
  };
  JQueryLite.prototype.addClass = function (name) {
    if (name) this.nodes.forEach(function (node) { node.classList.add(name); });
    return this;
  };
  JQueryLite.prototype.removeClass = function (names) {
    var parts = String(names || '').split(/\s+/).filter(Boolean);
    this.nodes.forEach(function (node) { parts.forEach(function (name) { node.classList.remove(name); }); });
    return this;
  };
  JQueryLite.prototype.on = function (event, handler) {
    this.nodes.forEach(function (node) { node.addEventListener(event, handler); });
    return this;
  };

  function wrap(promise) {
    return {
      done: function (callback) { promise.then(callback); return this; },
      fail: function (callback) { promise.catch(callback); return this; }
    };
  }

  function parseResponse(response) {
    return response.text().then(function (text) {
      var body = text ? JSON.parse(text) : null;
      if (!response.ok) {
        var error = new Error(response.statusText);
        error.responseJSON = body || {};
        throw error;
      }
      return body;
    });
  }

  function $(selector) { return new JQueryLite(selector); }
  $.getJSON = function (url) {
    return wrap(fetch(url, { credentials: 'same-origin' }).then(parseResponse));
  };
  $.ajax = function (options) {
    return wrap(fetch(options.url, {
      method: options.method || 'GET',
      credentials: 'same-origin',
      headers: options.contentType ? { 'Content-Type': options.contentType } : {},
      body: options.data
    }).then(parseResponse));
  };

  window.$ = window.jQuery = $;
})(window);
